const emails = items.map(item => {
  const msg = item.json;

  // from peut être un objet ou une string
  let from = '';
  if (typeof msg.from === 'string') {
    from = msg.from;
  } else if (msg.from?.text) {
    from = msg.from.text;
  } else if (msg.from?.value?.[0]) {
    const v = msg.from.value[0];
    from = v.name ? `${v.name} <${v.address}>` : v.address || '';
  }

  const subject = msg.subject || '(sans objet)';
  const date = msg.internalDate
    ? new Date(Number(msg.internalDate)).toISOString()
    : msg.date || new Date().toISOString();
  const snippet = msg.snippet || msg.text?.substring(0, 200) || '';

  return { id: msg.id || '', from, subject, date, snippet };
});

return [{ json: { emails, count: emails.length } }];

const emails = items[0].json.emails || [];

// ── 1. Résumé via Groq ──────────────────────────────────────
let summary = 'Résumé non disponible.';
let groqError = null;
try {
  const https = require('https');
  const GROQ_API_KEY = $env['GROQ_API_KEY'] || '';
  const prompt = emails.length === 0
    ? 'Aucun email reçu aujourd\'hui.'
    : emails.map((e, i) => `${i+1}. De: ${e.from}\n   Objet: ${e.subject}\n   Extrait: ${e.snippet?.substring(0,150)}`).join('\n\n');

  const body = JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: 'Tu es un assistant qui résume des emails professionnels en français, de manière concise et structurée.' },
      { role: 'user', content: `Voici les emails reçus aujourd\'hui. Fais un résumé concis en 3 à 5 bullet points :\n\n${prompt}` }
    ],
    temperature: 0.5,
    max_tokens: 400
  });

  const data = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.groq.com',
      path: '/openai/v1/chat/completions',
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${GROQ_API_KEY}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body)
      }
    }, res => {
      let raw = '';
      res.on('data', c => raw += c);
      res.on('end', () => resolve(JSON.parse(raw)));
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });

  if (data.error) throw new Error(JSON.stringify(data.error));
  summary = data.choices?.[0]?.message?.content || summary;
} catch (err) {
  groqError = err.message;
}

// ── 2. Sauvegarder mailstoday.json ──────────────────────────
const fs = require('fs');
const outputPath = $env['MAILSTODAY_PATH'] || 'mailstoday.json';
const output = { generatedAt: new Date().toISOString(), summary, emails };
fs.writeFileSync(outputPath, JSON.stringify(output, null, 2), 'utf-8');

return [{ json: { success: true, emailCount: emails.length, summary, groqError } }];
